/* eslint-disable no-console */
import { SdoSender } from '../../rest';
export class SenderService {
    constructor(configuration, debug) {
        this.senderClient = new SdoSender(configuration);
        this.debug = debug;
    }
    async listUserNumbers(page, limit) {
        const response = await this.senderClient.listUserNumbers(page, limit);
        if (this.debug)
            console.log(`response: ${JSON.stringify(response.data, null, 2)}`);
        return response.data;
    }
}
